// // This module converts a 4-bit binary input into a 4-bit Gray code output. The output bits are generated where the first output bit (z1) is directly assigned the value of the second input bit (x2), while the subsequent output bits (z2, z3, z4) are determined by performing a bitwise AND operation between pairs of consecutive input bits (x1 with x2, x2 with x3, and x3 with x4).
module top_module(x1, x2, x3, x4, z1, z2, z3, z4);input x1, x2, x3, x4;
output reg z1, z2, z3, z4;

always @ (x1 or x2 or x3 or x4)
begin
	z1 = x1;
	z2 = x1 ^ x2;
	z3 = x2 ^ x3;
	z4 = x3 ^ x4;
end
endmodule
